code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

let input = [];
rl.on('line', (line) => {
    input.push(line);
}).on('close', () => {
    const t = parseInt(input[0]);
    for (let i = 1; i <= t; i++) {
        const [k, x] = input[i].split(' ').map(Number);
        console.log(7 * k - x);
    }
});
